//! Z-Image NextDiT forward parity bisect.
//!
//! Loads the PyTorch reference fixture (generated by `tools/zimage_pyref.py`)
//! and runs flame-core's NextDiT forward with intermediate capture, then
//! compares each named intermediate against the reference. First failing
//! cos_sim names the broken op.
//!
//! Usage:
//!   LD_LIBRARY_PATH=/home/alex/libtorch-cu124/libtorch/lib:$LD_LIBRARY_PATH \
//!     cargo run --release --bin zimage_parity -- \
//!         --fixture flame-core/tests/pytorch_fixtures/zimage_forward_ref.safetensors \
//!         --model /home/alex/.serenity/models/checkpoints/z_image_base_bf16.safetensors
//!
//! Concat-order asymmetry: the Python reference concatenates `[image, cap]`
//! while flame-core concatenates `[cap, image]`. For unified-prefixed
//! intermediates the harness slices each side and compares per-half.

use flame_core::serialization::{load_file, load_file_filtered};
use flame_core::{global_cuda_device, DType, Result, Shape, Tensor};
use inference_flame::models::zimage_nextdit::NextDiT;
use std::collections::HashMap;
use std::path::PathBuf;

const CAP_LEN: usize = 512;
const IMG_LEN: usize = 1024;

#[derive(Default)]
struct Args {
    fixture: PathBuf,
    model: PathBuf,
}

fn parse_args() -> Args {
    let mut a = Args::default();
    a.fixture = PathBuf::from(
        "flame-core/tests/pytorch_fixtures/zimage_forward_ref.safetensors",
    );
    a.model = PathBuf::from(
        "/home/alex/.serenity/models/checkpoints/z_image_base_bf16.safetensors",
    );
    let argv: Vec<String> = std::env::args().collect();
    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--fixture" => { i += 1; a.fixture = PathBuf::from(&argv[i]); }
            "--model"   => { i += 1; a.model   = PathBuf::from(&argv[i]); }
            _ => {}
        }
        i += 1;
    }
    a
}

/// `to_vec_f32` reads raw storage and ignores view offsets/strides — so any
/// caller that wants the LOGICAL elements of a narrow/permute view must
/// materialize first via `.contiguous()`. We do that here so all downstream
/// comparisons see the right slice.
fn host_f32(t: &Tensor) -> Vec<f32> {
    let c = t.contiguous().expect("contiguify for host read");
    c.to_vec_f32().expect("to_vec_f32")
}

fn cos_sim_f32(got: &Tensor, expected: &Tensor) -> f64 {
    let gf = host_f32(got);
    let ef = host_f32(expected);
    assert_eq!(gf.len(), ef.len(),
        "cos_sim length mismatch: got {} vs expected {}", gf.len(), ef.len());
    let dot: f64 = gf.iter().zip(ef.iter()).map(|(a, b)| *a as f64 * *b as f64).sum();
    let na: f64 = gf.iter().map(|x| (*x as f64).powi(2)).sum::<f64>().sqrt();
    let nb: f64 = ef.iter().map(|x| (*x as f64).powi(2)).sum::<f64>().sqrt();
    if na == 0.0 || nb == 0.0 { 0.0 } else { dot / (na * nb) }
}

fn max_abs_diff(got: &Tensor, expected: &Tensor) -> f32 {
    let gf = host_f32(got);
    let ef = host_f32(expected);
    gf.iter().zip(ef.iter()).map(|(a, b)| (a - b).abs()).fold(0.0f32, f32::max)
}

fn report(name: &str, got: &Tensor, expected: &Tensor) -> (f64, f32) {
    let cos = cos_sim_f32(got, expected);
    let mad = max_abs_diff(got, expected);
    let marker = if cos >= 0.999 { "✓" } else if cos >= 0.99 { "?" } else { "✗" };
    println!("  {marker} {:48} cos={:.6}  max_abs_diff={:.4e}  shape={:?}",
        name, cos, mad, got.shape().dims());
    (cos, mad)
}

fn main() -> Result<()> {
    let args = parse_args();
    let device = global_cuda_device();

    println!("=== Z-Image forward parity bisect ===");
    println!("fixture: {}", args.fixture.display());
    println!("model:   {}", args.model.display());

    // 1. Load fixture (PyTorch reference + inputs).
    println!("\n[+] Loading fixture...");
    let fixture: HashMap<String, Tensor> = load_file(&args.fixture, &device)
        .expect("load fixture");
    println!("    {} tensors", fixture.len());

    // 2. Extract inputs.
    let x_in = fixture.get("input.x").expect("input.x");
    let cap_in = fixture.get("input.cap_feats").expect("input.cap_feats");
    let t_in = fixture.get("input.t").expect("input.t");

    // Python's input.x is [B, C, F=1, H, W]; flame-core NextDiT expects [B, C, H, W].
    let xd = x_in.shape().dims().to_vec();
    assert_eq!(xd.len(), 5, "expected input.x with shape [B,C,1,H,W], got {:?}", xd);
    assert_eq!(xd[2], 1, "expected F=1, got {}", xd[2]);
    let x_4d = x_in.reshape(&[xd[0], xd[1], xd[3], xd[4]])?;

    // Convert Python t (passed directly to forward) → Rust σ.
    // Rust's NextDiT does internal_t = (1-σ)*1000; Python does t*1000.
    // Match internal_t by setting σ = 1 - t.
    let t_data = t_in.to_vec_f32()?;
    println!("[+] Python t = {:.4} → Rust σ = {:.4}", t_data[0], 1.0 - t_data[0]);
    let sigma_data: Vec<f32> = t_data.iter().map(|t| 1.0 - t).collect();
    let sigma = Tensor::from_vec_dtype(
        sigma_data, t_in.shape().clone(), device.clone(), DType::BF16,
    )?;

    let cap_feats = cap_in.to_dtype(DType::BF16)?;

    // 3. Load model.
    println!("\n[+] Loading Z-Image transformer ({} ...)",
        args.model.file_name().unwrap().to_string_lossy());
    let weights = load_file_filtered(&args.model, &device, |_| true)?;
    println!("    {} tensors", weights.len());
    let mut model = NextDiT::new_resident(weights, device.clone());

    // 4. Run forward with capture.
    println!("\n[+] Running forward_with_capture...");
    let mut capture: HashMap<String, Tensor> = HashMap::new();
    let final_out = model.forward_with_capture(&x_4d, &sigma, &cap_feats, &mut capture)?;
    println!("    captured {} intermediates, output shape {:?}",
        capture.len(), final_out.shape().dims());

    // 5. Compare.
    println!("\n=== Per-stage parity (cap-half vs python cap; img-half vs python img) ===");
    let mut first_bad: Option<String> = None;

    // Direct shape-matching captures (no concat reorder).
    let direct_keys: &[(&str, &str)] = &[
        ("t_emb", "t_emb"),
        // Python hooks pre-pad; Rust captures pre-pad as well. Both are [seq, dim] or [B, seq, dim].
        ("x_after_embedder", "x_after_embedder"),
        ("cap_after_embedder", "cap_after_embedder"),
        ("x_after_noise_refiner_00", "x_after_noise_refiner_00"),
        ("x_after_noise_refiner_01", "x_after_noise_refiner_01"),
        ("cap_after_context_refiner_00", "cap_after_context_refiner_00"),
        ("cap_after_context_refiner_01", "cap_after_context_refiner_01"),
    ];

    for (rust_key, py_key) in direct_keys {
        let Some(got) = capture.get(*rust_key) else {
            println!("  SKIP {rust_key}: not captured");
            continue;
        };
        let Some(expected) = fixture.get(*py_key) else {
            println!("  SKIP {rust_key}: no fixture {py_key}");
            continue;
        };
        // Reshape if needed: Python's pre-pad embedder outputs are [seq, dim]
        // while Rust's are [1, seq, dim] (post `linear_*` with batch retained).
        let (got, expected) = align_shapes(got, expected)?;
        let (cos, _) = report(rust_key, &got, &expected);
        if cos < 0.99 && first_bad.is_none() {
            first_bad = Some(rust_key.to_string());
        }
    }

    // Unified captures: Rust [cap(512), img(1024)], Python [img(1024), cap(512)].
    let unified_keys: Vec<String> = std::iter::once("unified_initial".to_string())
        .chain((0..30).map(|i| format!("unified_after_layer_{:02}", i)))
        .collect();

    for k in &unified_keys {
        let Some(got) = capture.get(k) else {
            println!("  SKIP {k}: not captured");
            continue;
        };
        let Some(expected) = fixture.get(k) else {
            println!("  SKIP {k}: no fixture");
            continue;
        };
        // Slice halves.
        let rust_cap = got.narrow(1, 0, CAP_LEN)?;
        let rust_img = got.narrow(1, CAP_LEN, IMG_LEN)?;
        let py_img = expected.narrow(1, 0, IMG_LEN)?;
        let py_cap = expected.narrow(1, IMG_LEN, CAP_LEN)?;
        let (cap_cos, _) = report(&format!("{k}.cap"), &rust_cap, &py_cap);
        let (img_cos, _) = report(&format!("{k}.img"), &rust_img, &py_img);
        if (cap_cos < 0.99 || img_cos < 0.99) && first_bad.is_none() {
            first_bad = Some(k.clone());
        }
    }

    // after_final_layer: Rust captured image-only [1, 1024, 64].
    // Python captured full unified [1, 1536, 64]; image is at [:, :IMG_LEN].
    if let (Some(got), Some(expected)) =
        (capture.get("after_final_layer_img"), fixture.get("after_final_layer"))
    {
        let py_img = expected.narrow(1, 0, IMG_LEN)?;
        let (cos, _) = report("after_final_layer_img", got, &py_img);
        if cos < 0.99 && first_bad.is_none() {
            first_bad = Some("after_final_layer_img".to_string());
        }
    }

    // Final output. Rust returns negated; Python returns raw.
    if let Some(expected) = fixture.get("output") {
        let neg_expected = expected.mul_scalar(-1.0)?;
        // Python output [16, 1, 64, 64], Rust [1, 16, 64, 64]. Reshape.
        let pe = neg_expected.shape().dims().to_vec();
        let total: usize = pe.iter().product();
        let neg_expected = neg_expected.reshape(&[total])?;
        let got = final_out.reshape(&[total])?;
        let (cos, _) = report("output (-rust vs python)", &got, &neg_expected);
        if cos < 0.99 && first_bad.is_none() {
            first_bad = Some("output".to_string());
        }
    }

    println!("\n=== Result ===");
    match first_bad {
        Some(name) => {
            println!("FIRST DIVERGENCE: {name}");
            std::process::exit(1);
        }
        None => {
            println!("ALL PASS (cos >= 0.99 everywhere)");
        }
    }
    Ok(())
}

/// Bring `got` and `expected` to the same shape so cos_sim's element-count
/// assertion passes. We trust elements-equal and reshape into a flat 1-D.
fn align_shapes(got: &Tensor, expected: &Tensor) -> Result<(Tensor, Tensor)> {
    let g_total: usize = got.shape().dims().iter().product();
    let e_total: usize = expected.shape().dims().iter().product();
    assert_eq!(g_total, e_total,
        "elem count mismatch: got {:?} ({g_total}) vs expected {:?} ({e_total})",
        got.shape().dims(), expected.shape().dims());
    Ok((got.reshape(&[g_total])?, expected.reshape(&[e_total])?))
}

